    ('ERA III 1, 103 (3)', 'N', NULL, NULL, 'XII 346', 1, 1, 1, NULL, '<Lisasin pealkirja, koguja ja esitaja kommentaare. Paneksin selle labajala-tüüpi laulude hulka, mitte 2-realistesse viisidesse. Tekst ei ole regivärsiline.>', 1),
    ('ERA III 1, 11 (2)', 'ERA II 10, 727 (2)', NULL, NULL, 'XIII 285', 1, 1, 1, NULL, '<Parandasin teksti viite>', 1),
    ('ERA III 1, 127 (2)', 'ERA II 21, 155/6', 'ERA, Fon. 258 a', NULL, 'XII 358 / 364', 1, 1, 1, NULL, '<Selge, lõpuosas mingi kahjustus. Märgitud: (Fon. N 1 a)><Ilmselt on välitöödel tehtud noodistust hiljem fonogrammi järgi täpsustatud. Lisasin heli viite. Teksti juures on vanad fonogrammi numbrid. Koguja on teksti jaganud a ja b osaks, digiteerija on jaganud ka fonogrammi.>', 1),
    ('ERA III 1, 127 (2)', 'ERA II 21, 156/8', 'ERA, Fon. 258 a1', NULL, 'XV 389', 1, 1, 1, NULL, '<Selge, algul vaikset juttu (13 sek). Märgitud: Fon. N 1 b.><Ilmselt on välitööde noodistust hiljem fonogrammi järgi täpsustatud. Parandasin teksti viite: oli ERA II 155/8 (3), lisasin heli viite. Teksti juures on vanad fonogrammi numbrid ja ilmsalt pärast fonogrammi kuulamist lisatud märkusi, sealhulgas mõned noodid.>', 1),
    ('ERA III 1, 129 (5)', 'ERA II 21, 167/8 (8)', 'ERA, Fon. 261 a', NULL, 'XII 429', 1, 1, 1, NULL, '<Selge,  noodist pikem><Parandasin heli viite (oli Fon. 262 b.), täpsustasin laululiiki ja -tüüpi kuulamise põhjal. Noodi ja teksti juures vanad fonogramminumbrid.>', 1),
    ('ERA III 1, 13 (8)', 'ERA II 10, 729 (7)', NULL, NULL, 'XIII 282', 1, 1, 1, NULL, '<Pole klassikaline 2-reline viis: Siin on küll 16 pos-i, aga teksti struktuur on teistsugune: värsi esimene pool kordub 3 x ja järgneb lõpp.>', 1),
    ('ERA III 1, 130 (5)', 'ERA II 21, 170 (11)', 'ERA, Fon. 262 b', NULL, 'I 571', 1, 1, 1, NULL, '<Selge, tekstist ja noodist pikem ><Lisasin ka midagi (teksti viite?) Noodi ja teksti juures vanad fonogramminumbrid.>', 1),
    ('ERA III 1, 130 (7)', 'ERA II 21, 171 (12)', 'ERA, Fon. 262 c', NULL, 'I 32', 1, 1, 1, NULL, '<Arusaadav, noodist pikem ><Lisasin teksti viite, parandasin vormi. Ei ole noodistatud salvestuselt. Noodi ja teksti juures vanad fonogramminumbrid.>', 1),
    ('ERA III 1, 132 (11)', 'ERA II 21, 175/7 (17)', 'ERA, Fon. 264 b', NULL, NULL, 1, 1, 1, NULL, '<Selge, noodist pikem, tekst veel pikem><Lisasin teksti viite, laulutüübi. Noodi ja teksti juures vanad fonogramminumbrid.>', 1),
    ('ERA III 1, 132 (13)', 'ERA II 21, 179 (19)', 'ERA, Fon. 265 a, b', NULL, 'XV 335', 1, 1, 1, NULL, '<Heli ei ole enam, fonogramm katki><Parandasin esitaja nime Kõigesaar. Nooti on vist täiendatud heli järgi. Noodi ja teksti juures vanad fonogramminumbrid.>', 1),
    ('ERA III 1, 133 (15)', 'ERA II 21, 181/2 (23)', 'ERA, Fon. 265 c', NULL, 'XV 396', 1, 1, 1, NULL, '<Heli ei ole enam, fonogramm katki><Nooti on ilmselt Koch fonogrammi järgi hiljem täpsustanud. Noodi ja teksti juures vanad fonogramminumbrid.>', 1),
    ('ERA III 1, 134 (17)', 'ERA II 21, 184 (25)', 'ERA, Fon. 266 b', NULL, 'II 211', 1, 1, 1, NULL, '<Selge, noodist pikem, vastab tekstile><Lisasin teksti viite. Noodialune tekst erineb teistest: "mardisandid". Teksti ja nooti on ilmselt Koch fonogrammi järgi hiljem täpsustanud. Noodi ja teksti juures vanad fonogramminumbrid.>', 1),
    ('ERA III 1, 135 (19)', 'ERA II 21, 185/6 (27)', 'ERA, Fon. 267 b', NULL, 'II 331', 1, 1, 1, NULL, '<Väga ilus esitus, selge, noodist pikem, veidi erineb tekstist><Lisasin teksti viite, stroofi vormi. Teksti ja nooti on ilmselt Koch fonogrammi järgi hiljem täpsustanud. Tekst ja heli võivad olla eri variandid. Noodi ja teksti juures vanad fonogramminumbrid.>', 1),
    ('ERA III 1, 135 (20)', 'ERA III 136/7 (28)', 'ERA, Fon. 268 a, b', NULL, 'VIII 251', 1, 1, 1, NULL, '<Selge, ilus, tekstist erinev variant.><See on järjekindel 4-realine viis, ei kuulu siia. Tekst ja noot ei vasta helile, mis on pikem ja lauldakse teise struktuuriga. Lisasin teksti viite, vormi. Noodi ja teksti juures vanad fonogramminumbrid.>', 1),
    ('ERA III 1, 136 (24)', 'ERA II 21, 189/90 (32)', NULL, NULL, 'XV 445', 1, 1, 1, NULL, '<Parandasin lauliku nime: Granberg. Noodi ja teksti juures vanad fonogramminumbrid.>', 1),
    ('ERA III 1, 137 (28)', 'ERA II 21, 193/4 (38)', 'ERA, Fon. 269 a', NULL, 'VIII 231', 1, 1, 1, NULL, '<Heli ei ole enam, fonogramm katki><Parandasin lauliku nime: Granberg. Lisasin teksti viite. Noodi ja teksti juures vanad fonogramminumbrid.>', 1),
    ('ERA III 1, 137 (29)', 'ERA II 21, 195/7 (40)', 'ERA, Fon. 266 c', NULL, 'VIII 159', 1, 1, 1, NULL, '<Selge, ilus, tekstist ja noodist veidi erinev variant. ><Lisasin teksti viite, esitaja nime ja andmed. Tekst ja heli/noot eri variandid (2 või 3), heli on noodist pikem, aga noodi variatsiooni pole mujal. Noodi ja teksti juures vanad fonogramminumbrid.>', 1),
    ('ERA III 1, 138 (33)', 'ERA II 21, 202/3 (44)', 'ERA, Fon. 270 a', NULL, 'VI 773', 1, 1, 1, NULL, '<Selge, noodist pikem, tekst veel pikem.><Lisasin teksti viite. Noodi ja teksti juures vanad fonogramminumbrid.>', 1),
    ('ERA III 1, 139 (36)', 'ERA II 21, 207 (50)', NULL, NULL, 'VI 855', 1, 1, 1, NULL, '<Lisasin teksti viite>', 1),
    ('ERA III 1, 139 (37)', 'ERA II 21, 207/8 (51)', 'ERA, Fon. 270 b', NULL, 'XV 439', 1, 1, 1, NULL, '<Arusaadav. Heli pikem, aga noodis üks värss, mis puudub salvestuselt.><Noodi ja teksti juures vanad fonogramminumbrid.>', 1),
    ('ERA III 1, 140 (40)', 'ERA II 21, 210 (54)', NULL, NULL, 'XII 428', 1, 1, 1, NULL, '<Lisasin vormi. Ma ei saa aru, mille põhjal see temporühm on määratud.>', 1),
    ('ERA III 1, 140 (42)', 'ERA II 21, 211 (56)', 'ERA, Fon. 270 d', NULL, 'VII 137', 1, 1, 1, NULL, '<Selge><Lisasin heli ja teksti viite, viisi vormi. Noodi ja teksti juures vanad fonogramminumbrid.>', 1),
    ('ERA III 1, 140 (44)', 'ERA II 21, 213/4 (59)', NULL, NULL, 'XII 427', 1, 1, 1, NULL, '<Täpsustasin teksti viidet, lsasin vormi.>', 1),
    ('ERA III 1, 141 (46)', 'ERA II 21, 214/5 (61)', NULL, NULL, 'XIII 221', 1, 1, 1, NULL, '<Lisasin teksti viite, vormi>', 1),
    ('ERA III 1, 141 (49)', 'ERA II 21, 217/8 (65)', NULL, NULL, 'XI 10', 1, 1, 1, NULL, '<Parandasin valla>', 1),
    ('ERA III 1, 142 (51)', 'ERA II 21, 219 (67)', NULL, NULL, 'IX 180', 1, 1, 1, NULL, NULL, 1),
    ('ERA III 1, 142 (55)', 'ERA II 21, 223 (71)', NULL, NULL, 'XV 313', 1, 1, 1, NULL, NULL, 1),
    ('ERA III 1, 147 (59)', 'ERA II 21, 227/8 (77)', NULL, NULL, 'VIII 426', 1, 1, 1, NULL, NULL, 1),
    ('ERA III 1, 147 (60)', 'ERA II 21, 228 (78)', NULL, NULL, 'XIII 562', 1, 1, 1, NULL, '<Siin oli küsimus: "Dbl. Vt. õitsilaulud". Andmebaasi piires see pole dubleeritud. Parandasin valla, lisasin teksti viite.>', 1),
    ('ERA III 1, 147 (61)', 'ERA II 21, 229 (79)', NULL, NULL, 'X 87', 1, 1, 1, NULL, '<Lisasin teksti viite, parandasin valla.>', 1),
    ('ERA III 1, 147 (62)', 'ERA II 21, 229/30 (80)', NULL, NULL, 'XII 358 / 363', 1, 1, 1, NULL, '<Lisasin teksti viite>', 1),
    ('ERA III 1, 147 (63)', 'ERA II 21, 230/1 (81)', NULL, NULL, 'IX 48', 1, 1, 1, NULL, NULL, 1),
    ('ERA III 1, 15 (15)', 'ERA II 10, 731 (15)', NULL, NULL, 'VII', 1, 1, 1, NULL, '<Muutsin tüüpi>', 1),
    ('ERA III 1, 153 (88)', 'ERA II 21, 257/9 (109)', 'ERA, Fon. 272 d', NULL, 'XIII 391', 1, 1, 1, NULL, '<Selge><Lisasin heli viite, vormi, noodis ja tekstis vanad fonogrammi numbrid. Noodistatud vist salvestusest sõltumata.>', 1),
    ('ERA III 1, 155 (95)', 'ERA II 21, 264/5 (116)', NULL, NULL, 'XI 242', 1, 1, 1, NULL, '<Lisasin heli viite. Noodis ja tekstis vanad fonogrammi numbrid.>', 1),
    ('ERA III 1, 155 (98)', 'ERA II 21, 266 (119)', 'ERA, Fon. 274 c', NULL, 'XII 358 / 362', 1, 1, 1, NULL, '<Selge, pikkus vastab tekstile><Lisasin teksti viite, laulutüübi. Noodis ja tekstis vanad fonogrammi numbrid. Noodistatud ei ole fonogrammi järgi.>', 1),
    ('ERA III 1, 158 (113)', 'ERA II 21, 278/9 (134)', NULL, NULL, 'X 64', 1, 1, 1, NULL, '<Lisasin teksti viite, ei leia laulutüübile inime...>', 1),
    ('ERA III 1, 16 (18)', 'ERA II 10, 732 (18)', NULL, NULL, 'XIV 613', 1, 1, 1, NULL, '<Leiutasin laulutüübi...>', 1),
    ('ERA III 1, 30 (25)', 'ERA II 6, 293/4 (6)', NULL, NULL, '429', 1, 1, 1, NULL, '<Parandasin lauliku nime: Leitorp>', 1),
    ('ERA III 1, 31 (28)', 'ERA II 6, 306/7 (1)', NULL, NULL, 'VII 129', 1, 1, 1, NULL, '<Täiendasin laulikute andmeid>', 1),
    ('ERA III 1, 337', 'ERA II 21, 161/2 (3)', 'ERA, Fon. 260 a', NULL, 'X 270', 1, 1, 1, NULL, '<Salvestusel kaks varianti: kiirem, segasem (lühike) ja aeglasem, selgem (pikem). Arusaadav. Originaalis heli kohta: "rulli algus, hiljem segane" (noot), "kiirus 2/3, endise 1/4 asemel, fonogr. nõrk" (tekst).><Noodistatud fonogrammi järgi, aga pole täpne. Lisasin teksti viite,>', 1),
    ('ERA III 1, 35 (50)', 'ERA II 6, 348 (7)', NULL, NULL, 'VI 217', 1, 1, 1, NULL, '<Lisasin teksti viite, parandasin vormi AA. Viisi vorm ei ole kindel 2-realine, sest on noodistatud 3 värssi.>', 1),
    ('ERA III 1, 36 (53)', 'ERA II 7, 394 (8)', NULL, NULL, 'XIII 505', 1, 1, 1, NULL, '<Laulutüübiks oli keegi pannud "Laisa naise tapmine" (!). Lisasin teksti viite jm andmed, muutsin tüübi. Noot jätab ka võimaluse, et see on 4-realine viis. Vrdl ERA III 1, 38 (59+60)>', 1),
    ('ERA III 1, 37 (56)', 'N', NULL, NULL, 'VI 365', 1, 1, 1, NULL, NULL, 1),
    ('ERA III 1, 38 (59, 60)', 'ERA II 6, 170/1 (2)', NULL, NULL, 'XIII 506', 1, 1, 1, NULL, '<Noot jätab võimaluse, et see on ka 4-realine viis. Vrdl ERA III 1, 36 (53). Teksti üleskirjutus on tehtud vist eraldi, kui viisikogujat polnud kohal.>', 1),
    ('ERA III 1, 38 (59, 60)', 'ERA II 7, 395/6 (13)', NULL, NULL, 'XIII 506', 1, 1, 1, NULL, '<Noot jätab võimaluse, et see on ka 4-realine viis. Vrdl ERA III 1, 36 (53).>', 1),
    ('ERA III 1, 38 (61)', 'ERA II 6, 172 (8)', NULL, NULL, 'X 158', 1, 1, 1, NULL, '<Parandasin teksti viite.>', 1),
    ('ERA III 1, 38 (62)', 'ERA II 7, 396 (14)', NULL, NULL, 'X 78', 1, 1, 1, NULL, NULL, 1),
    ('ERA III 1, 43 (63)', 'ERA II 6, 173/4 (10)', NULL, NULL, 'XV 334', 1, 1, 1, NULL, NULL, 1),
    ('ERA III 1, 43 (64)', 'ERA II 6, 173 (9)', NULL, NULL, 'XI 207', 1, 1, 1, NULL, '<Arvatavasti viis ja tekst kirjutatud eri esituste järgi.>', 1),
    ('ERA III 1, 43 (65)', 'ERA II 7, 396 (15)', NULL, NULL, 'VI 204', 1, 1, 1, NULL, '<Lisasin teksti viite, täiendasin andmeid.>', 1),
    ('ERA III 1, 47 (77)', 'ERA II 7, 397 (20)', NULL, NULL, 'VI 649', 1, 1, 1, NULL, '<Lisasin teksti viite, esitaja andmeid, kasutasin ka ERA II 6, 537.>', 1),
    ('ERA III 1, 51 (89)', 'ERA II 6, 538 (1)', NULL, NULL, 'X 98', 1, 1, 1, NULL, '<Tekst kogus ja noodi all veidi erinevad. Teksti üleskirjutus võib olla dikteeritud, sest pole esitusega seotud lisasilpe märgitud. Täiendasin andmeid.>', 1),
    ('ERA III 1, 52 (93)', 'ERA II 6, 544/5 (2) / ERA II 7, 409 (93)', NULL, NULL, 'XIII 431', 1, 1, 1, NULL, '<Parandasin esitaja soo :-), täiendasin andmeid. Lisasin teise teksti viite, tekstid erinevad üksikutes detailides.>', 1),
    ('ERA III 1, 52 (95)', 'ERA II 6, 551/2 (7) / ERA II 7, 410 (36)', NULL, NULL, 'XIII 635', 1, 1, 1, NULL, '<Täiendasin andmeid. Lisasin teise teksti viite, tekstid võivad olla erinevad esitused.>', 1),
    ('ERA III 1, 54 (102)', 'ERA II 6, 440 (1)', NULL, NULL, 'X 174', 1, 1, 1, NULL, NULL, 1),
    ('ERA III 1, 55 (104)', 'ERA II 6, 447 (1) / ERA II 7, 416 (48)', NULL, NULL, 'VI 295, VI 255 järel', 1, 1, 1, NULL, '<Lisasin teksti viited (teise võtsin viisiduplikaadist), täiendasin esitaja andmeid. Laulmisel on silbid redutseerunud, võrreldes teksti üleskirjutusega - kas ehk tekst on kirjutatud dikteerimise järgi?>', 1),
    ('ERA III 1, 55 (104)', 'ERA II 7, 416 (48)', NULL, NULL, NULL, 1, 1, 1, NULL, '<See on duplikaat, läheb andmebaasist välja. Selle teksti viide tuleb lisada teisele samale viisile - tehtud.>', 1),
    ('ERA III 1, 58 (114)', 'ERA II 6, 427 (23)', NULL, NULL, 'VIII 154', 1, 1, 1, NULL, '<Siin on samal välitööl kogutud sama laulu kattuvad tekstivariandid (erinevus detailides) tehtud eri kirjeteks, teistel juhtudel mitte. Vrdl. ERA III 1, 52 (93, 95, 96). Kas panna siin ka kokku? Kas panna siin ka kokku? Vrdl ERA II 7, 419 (53)>', 1),
    ('ERA III 1, 58 (114)', 'ERA II 7, 419 (53)', NULL, NULL, 'VIII 154', 1, 1, 1, NULL, '<Siin on samal välitööl kogutud sama laulu praktiliselt kattuvad tekstivariandid (erinevus detailides) tehtud eri kirjeteks, eelmistel juhtudel mitte ERA III 1, 52 (93, 95, 96). Kas panna siin ka kokku? Vrdl ERA II 6, 427 (23)>', 1),
    ('ERA III 1, 63 (119)', 'ERA II 7, 419 (55)', NULL, NULL, 'VI 802', 1, 1, 1, NULL, '<See ei ole 2-realine regiviis, on ringmängu vahelaul: värss ja refrään>', 1),
    ('ERA III 1, 64 (125)', 'N', NULL, NULL, '389', 1, 1, 1, NULL, '<See ei ole 2-realine regiviis, on uuem, ei ole regilaul>', 1),
    ('ERA III 1, 66 (131)', 'N', NULL, NULL, 'VI 348', 1, 1, 1, NULL, '<Lisasin esitaja andmeid>', 1),
    ('ERA III 1, 66 (134)', 'N', NULL, NULL, '499', 1, 1, 1, NULL, '<See ei ole 2-realine regilaul: on 4-realine viis, riimiline salmilaul. Andmeid: ERA II 7, 431>', 1),
    ('ERA III 1, 68 (139)', 'N', NULL, NULL, '388', 1, 1, 1, NULL, '<See ei ole 2-realine regiviis, on uuem, ei ole regilaul>', 1),
