    ('ERA III 1, 77 (175)', 'ERA II 7, 438 (94)', NULL, NULL, 'X 228', 1, 1, 1, NULL, NULL, 1),
    ('ERA III 1, 78 (177)', 'ERA II 7, 440 (97), (98)', NULL, NULL, 'VI 368', 1, 1, 1, NULL, '<Lisasin tekstide viited, parandasin esitaja nime (Marie) ja lisasin andmeid>', 1),
    ('ERA III 1, 78 (179)', 'N', NULL, NULL, 'I 857.1', 1, 1, 1, NULL, NULL, 1),
    ('ERA III 1, 84 (183)', 'N / ERA II 7, 51/2 (1, 2)', NULL, NULL, 'II 336', 1, 1, 1, NULL, '<Vbl on sama viisiga ka ERA II 7, 443 (106), (108), 444 (110). Lisasin viisile tekstide numbrid Saati tekstikogu viidete põhjal.>', 1),
    ('ERA III 1, 84 (183)', 'ERA II 7, 442/3 (104)', NULL, NULL, NULL, 1, 1, 1, NULL, '<Vbl on sama viisiga ka ERA II 7, 443 (106), (108), 444 (110). Lisasin viisile tekstide numbrid Saati tekstikogu viidete põhjal.>', 1),
    ('ERA III 1, 84 (183)', 'ERA II 7, 443 (105)', NULL, NULL, NULL, 1, 1, 1, NULL, '<Vbl on sama viisiga ka ERA II 7, 443 (106), (108), 444 (110). Lisasin viisile tekstide numbrid Saati tekstikogu viidete põhjal.>', 1),
    ('ERA III 1, 84 (183)', 'ERA II 7, 443 (107)', NULL, NULL, NULL, 1, 1, 1, NULL, '<Vbl on sama viisiga ka ERA II 7, 443 (106), (108), 444 (110). Lisasin viisile tekstide numbrid Saati tekstikogu viidete põhjal.>', 1),
    ('ERA III 1, 84 (183)', 'ERA II 7, 443 (109)', NULL, NULL, NULL, 1, 1, 1, NULL, '<Vbl on sama viisiga ka ERA II 7, 443 (106), (108), 444 (110). Lisasin viisile tekstide numbrid Saati tekstikogu viidete põhjal.>', 1),
    ('ERA III 1, 84 (183)', 'ERA II 7, 444 (111)', NULL, NULL, NULL, 1, 1, 1, NULL, '<Vbl on sama viisiga ka ERA II 7, 443 (106), (108), 444 (110). Lisasin viisile tekstide numbrid Saati tekstikogu viidete põhjal.>', 1),
    ('ERA III 1, 84 (183)', 'ERA II 7, 444 (112) / ERA II 7, 53 (4)', NULL, NULL, NULL, 1, 1, 1, NULL, '<Vbl on sama viisiga ka ERA II 7, 443 (106), (108), 444 (110). Lisasin viisile tekstide numbrid Saati tekstikogu viidete põhjal.>', 1),
    ('ERA III 1, 84 (183)', 'ERA II 7, 444 (113) / ERA II 7, 137 (2)', NULL, NULL, NULL, 1, 1, 1, NULL, '<Vbl on sama viisiga ka ERA II 7, 443 (106), (108), 444 (110). Lisasin viisile tekstide numbrid Saati tekstikogu viidete põhjal.>', 1),
    ('ERA III 1, 84 (183)', 'ERA II 7, 444 (114) / ERA II 7, 136 (14)', NULL, NULL, NULL, 1, 1, 1, NULL, '<Vbl on sama viisiga ka ERA II 7, 443 (106), (108), 444 (110). Lisasin viisile tekstide numbrid Saati tekstikogu viidete põhjal.>', 1),
    ('ERA III 1, 84 (183)', 'ERA II 7, 444 (115) / ERA II 7, 79 (3)', NULL, NULL, NULL, 1, 1, 1, NULL, '<Vbl on sama viisiga ka ERA II 7, 443 (106), (108), 444 (110). Lisasin viisile tekstide numbrid Saati tekstikogu viidete põhjal.>', 1),
    ('ERA III 1, 84 (183)', 'ERA II 7, 444 (116)', NULL, NULL, NULL, 1, 1, 1, NULL, '<Vbl on sama viisiga ka ERA II 7, 443 (106), (108), 444 (110). Lisasin viisile tekstide numbrid Saati tekstikogu viidete põhjal.>', 1),
    ('ERA III 1, 84 (183)', 'ERA II 7, 444/5 (117)?', NULL, NULL, NULL, 1, 1, 1, NULL, '<Originaalis on ilmselt viga: siinse viisiga ei ole tekst ERA II 7, 444 (117), nagu koguja on sinna juurde märkinud, vaid selle teksti jaoks on ka eraldi viis ERA III 1, 85 (189) (see pole 2-realine, tekst uuem).>', 1),
    ('ERA III 1, 84 (183)', 'ERA II 7, 445 (118) / ERA II 7, 136 (14)', NULL, NULL, NULL, 1, 1, 1, NULL, '<Vbl on sama viisiga ka ERA II 7, 443 (106), (108), 444 (110). Lisasin viisile tekstide numbrid Saati tekstikogu viidete põhjal.>', 1),
    ('ERA III 1, 85 (190)', 'ERA II 7, 93 (37, 37)', NULL, NULL, '434', 1, 1, 1, NULL, '<Noodistatud on ainult refrään>', 1),
    ('ERA III 1, 93 (218)', 'ERA II 7, 98 (15)', NULL, NULL, 'IX 157', 1, 1, 1, NULL, '<Sisestasin andmebaasi. 7.01.2020>', 1),
    ('ERA III 2, 127 (124 a)', 'ERA II 17, 278/9 (168)', 'ERA, Fon. 225 a', NULL, 'XII 360 / ? 1681', 1, 1, 1, NULL, '<heli pikem><Lisasin lauliku (helisalvestuste nimestikust), teksti viite, stroofi vormi (salvestuse põhjal), tegevuse jne. Märkuste lahtris oli nr 1681, mis võis olla vigane viide tekstile 168). Kustutasin selle. Tekst, viis ja helisalvestus on tõenäoliselt jäädvustatud eraldi. Noodistuste vihikus on sama pealkiri "Kihnu teopoisi laul" kirjutatud laulu ERA II 2, 129 (124) ette, millel on sama viis, aga algab teistsuguse värsiga. Laulutekstis on 4 värssi tumeda tindiga kaetud.>', 1),
    ('ERA III 2, 127 (124)', 'N', NULL, NULL, '1681', 1, 1, 1, NULL, '<Sama pealkiri on teistsuguse algusvärsi ja viisiga laulul ERA III 2, 129 (124).>', 1),
    ('ERA III 2, 13 (4)', 'ERA II 17, 80/4, 84/9 (41)', 'ERA, Fon. 211 a1, a2', NULL, 'IV 425', 1, 1, 1, NULL, '<a1) Kehv, tekst mõistetav üleskirjutuse abil. Noot ja heli arvatavalt eri esitused. Helisalvestuse värsid, võrreldes noodi ja tekstiga, osalt kattuvad, osalt erinevad ja teises järjekorraas. Noodis ja tekstis on värsse, mida salvestusel ei ole. a2) Lühem ja halvem salvestus, ei saa sõnadest aru.><Esituse kohta oli andmebaasis märgitud E+Ü ehk kahekesi, kuid see oli ilmselt nime ja hüüdnime vale tõlgendamine, helisalvestusel laulis üks inimene ja pole vihjeid 2 naise kohta. Parandasin. Noot ei ole tehtud arvatavasti nende salvestuste järgi.>', 1),
    ('ERA III 2, 139 (138)', 'N', NULL, NULL, 'XIV 569', 1, 1, 1, NULL, NULL, 1),
    ('ERA III 2, 15 (5)', 'ERA II 17, 91 (43)', 'ERA, Fon. 211 b', NULL, 'X 194', 1, 1, 1, NULL, '<Heli 1. värss kattub noodiga, heli on noodistusest pikem, halvasti arusaadav. ><Ei tea, kas noodistatud on salvestuse põhjal, sest noodistuse teist rida on salvestuselt raske välja kuulda. Tekstiga võrreldes tundub, on salvestusel teine variant.>', 1),
    ('ERA III 2, 165 (154)', 'ERA II 16, 388/9 (21)', 'ERA, Fon. 232 a', NULL, 'II 341', 1, 1, 1, NULL, '<Heli ja noot üsna ühed, samade algusvärssidega tekst pikem.><Lisasin teksti viite, parandasin esitaja nime (oli Jüri). Noodistusel võib olla kasutatud salvestust.>', 1),
    ('ERA III 2, 209 (194)', 'ERA II 17, 301 (183/4)', 'ERA, Fon. 235 a', NULL, 'II 376', 1, 1, 1, NULL, '<Heli on pikk ja selge, mitukümmend värssi, noodistusel algus ja variatsioonid. Ainult algusvärsi kordusosa on noodis salvestusest erinev - kas eksitus või teine variant. Tagaosa on kindlasti salvestuse järgi noodistatud. Teksti üleskirjutus on salvestusest pikem, olemasolevates osades nad üsna kattuvad. ><Noodistatud võib olla vähemalt osaliselt salvestuse põhjal, vbl on siiski salvestuse algusvärsi ja teksti aluseks teine variant. Muutsin vormi kuulamise põhjal AA-ks.>', 1),
    ('ERA III 2, 231 (214)', 'ERA II 17, 332 (208)', 'ERA, Fon. 239 d', NULL, 'II 374', 1, 1, 1, NULL, '<Heli on selge, kümmekond värssi, noodistusel algusvärss ja variatsioon.  Pisiasjades erineb salvestus tekstist.><Noodistatud võib olla salvestuse põhjal, teksti puhul siiski kahtlen.>', 1),
    ('ERA III 2, 231 (215)', 'ERA II 17, 332 (208)', 'ERA, Fon. 239 c, e', NULL, 'II 353', 1, 1, 1, NULL, '<c) Heli on selge, ei kattu noot-noodilt noodistusega.  e) Heli on selge, üks katkestus, 6 värssi, mis on noodistusele lähedasemad, kui Fon 239 c, kuid ei kattu noot-noodilt.><Noodistusel on üks viis (=viisitüüp), mida on salvestatud kahelt eri inimeselt. Siia tuleks teha salvestustest kaks eri varianti. Noodistus ei vasta täpselt kummalegi, on tõenäoliselt tehtud salvestustest eraldi, vbl kuulates mõlemat lauljat.>', 1),
    ('ERA III 2, 259 (242)', 'N', 'ERA, Fon. 244 a', NULL, 'V 59', 1, 1, 1, NULL, '<Heli on selge, paarkümmend värssi, noodistusel muuhulgas aga värss, mis salvestuselt puudub.><Noodistatud on arvatavasti salvestusest eraldi. Parandasin laulja nime Kauskopp. ERA II 17 on samalt laulikult teisi pulmalaulutekste.>', 1),
    ('ERA III 2, 261 (243)', 'ERA II 17, 348/9 (229)', NULL, NULL, 'XV 353', 1, 1, 1, NULL, '<Parandasin teksti viite (olis ERA II 21, 348/9 (21)), muutsin laulutüübi, enne oli "Minia õpetus". Parandasin endise laulja nime Kauskopp, asula Kivi.>', 1),
    ('ERA III 2, 261 (244)', 'N', NULL, NULL, 'V 166', 1, 1, 1, NULL, '<Parandasin endise laulja nime Kauskopp, asula Vigala>', 1),
    ('ERA III 2, 261 (245)', 'ERA II 17, 368/9 (249)', NULL, NULL, 'X 202', 1, 1, 1, NULL, '<Parandasin endise laulja nime Kauskopp, asula Kivi>', 1),
    ('ERA III 2, 267 (253)', 'N', NULL, NULL, 'XIV 570', 1, 1, 1, NULL, '<Parandasin endise laulja nime Kauskopp, asula Kivi>', 1),
    ('ERA III 2, 291 (280)', NULL, NULL, NULL, '404', 1, 1, 1, NULL, '<See on UL, läheb välja>', 1),
    ('ERA III 2, 31 (20)', 'N', NULL, NULL, 'IX 257', 1, 1, 1, NULL, '<Muutsin esitajaga seotud küsimärgid andmeteks.>', 1),
    ('ERA III 2, 33 (21)', 'N', NULL, NULL, 'XIII 611', 1, 1, 1, NULL, '<EI tea, millel põhineb tüübi määratlus ja Tedre seda tüübinime ei kasuta.>', 1),
    ('ERA III 2, 333 (310)', 'N', NULL, NULL, 'I 722', 1, 1, 1, NULL, NULL, 1),
    ('ERA III 2, 335 (311)', 'ERA II 17, 822/3 (31)', NULL, NULL, 'II 347', 1, 1, 1, NULL, NULL, 1),
    ('ERA III 2, 335 (312)', 'ERA II 17, 820/1 (26)', NULL, NULL, 'V 60', 1, 1, 1, NULL, '<Lisasin teksti viite>', 1),
    ('ERA III 2, 335 (313)', 'ERA II 17, 820 (25)', NULL, NULL, 'VI 347', 1, 1, 1, NULL, '<Lisasin teksti viite. Nimetasin ise laulutüübi.>', 1),
    ('ERA III 2, 337 (314)', 'ERA II 17, 821 (27)', NULL, NULL, 'X 183', 1, 1, 1, NULL, '<Lisasin teksti viite. Eelkäija on määranud laulutüübiks "Kubjas põrgus", ma panin küsimärgi, sest ei näe selle põhjust.>', 1),
    ('ERA III 2, 337 (316)', NULL, NULL, NULL, 'XIV 801', 1, 1, 1, NULL, NULL, 1),
    ('ERA III 2, 341 (318)', 'ERA II 17, 833 / ERA II 17, 838', NULL, NULL, 'IX 240', 1, 1, 1, NULL, '<Sama algusvärsiga on tekstikogus kaks laulu lk 833 ja 838. Minu eelkäija on märkinud viiside ja tekstide seosed järgmiselt, samas ma ei näe põhjendust: ERA III 2, 341 (318) - ERA II 17, 838; ERA III 2, 341 (319) ja (320) - ERA II 17, 831. Pealegi ei ole 831 üldse regivärsiline. Muutsin siin oma arvamust mööda. Ja Tedrel pole selle nimega laulutüüpi "Ei üht naist">', 1),
    ('ERA III 2, 341 (319)', 'ERA II 17, 833 / ERA II 17, 838', NULL, NULL, 'XIV 800', 1, 1, 1, NULL, '<Sama algusvärsiga on tekstikogus kaks laulu lk 833 ja 838. Minu eelkäija on märkinud viiside ja tekstide seosed järgmiselt, samas ma ei näe põhjendust: ERA III 2, 341 (318) - ERA II 17, 838; ERA III 2, 341 (319) ja (320) - ERA II 17, 831. Pealegi ei ole 831 üldse regivärsiline. Muutsin siin oma arvamust mööda.>', 1),
    ('ERA III 2, 341 (320)', 'ERA II 17, 833 / ERA II 17, 838', NULL, NULL, 'XIV 799', 1, 1, 1, NULL, '<Sama algusvärsiga on tekstikogus kaks laulu lk 833 ja 838. Minu eelkäija on märkinud viiside ja tekstide seosed järgmiselt, samas ma ei näe põhjendust: ERA III 2, 341 (318) - ERA II 17, 838ERA III 2, 341 (319) ja (320) - ERA II 17, 831. Pealegi ei ole 831 üldse regivärsiline. Muutsin siin oma arvamust mööda.>', 1),
    ('ERA III 2, 389 (360)', 'N', NULL, NULL, 'XIII 556', 1, 1, 1, NULL, NULL, 1),
    ('ERA III 2, 389 (361)', 'ERA II 17, 862', NULL, NULL, 'V 194', 1, 1, 1, NULL, '<Parandasin teksti viite ERA II 17, 821 (27)>', 1),
    ('ERA III 2, 43 (32)', 'ERA II 17, 122 (65)', 'ERA, Fon. 215 b', NULL, 'IV 429', 1, 1, 1, NULL, '<Kahisev, peaaegu arusaadav, 10 värssi, kattub tekstiga; noodistus on lühem, kuid üldiselt kattub heliga. ><Võib olla heli järgi noodistatud.>', 1),
    ('ERA III 2, 45 (33)', 'ERA II 17, 122/3 (66 a)', 'ERA, Fon. 215 c', NULL, 'II 396', 1, 1, 1, NULL, '<Selge salvestus, viisikäik ja laulutekst erinevad noodist - pole sama variant. Heli ja tekst natuke erinevad.><Ilmselt pole heli järgi noodistatud. Fonograafil on viis ERA III 2, 43 (32) mardilaulu sõnadega. Sellele viitab ka koguja märkus mardilaulu juures: "Lauldud ka viisil nr 32". Siin noodistatud mardilaulu viisi pole aga salvestatud, seega viisi poolest kuulub salvestus pigem teise laulu juurde või on eraldi variant. Vbl laulja esitas kaks korda eri viisidega. Kas tekstiosale võiks lisada (a).>', 1),
    ('ERA III 2, 45 (34)', 'ERA II 17, 122/3 (66 b)', 'ERA, Fon. 215 d', NULL, 'II 618', 1, 1, 1, NULL, '<Noot ja heli kattuvad pisiasjadeni, tekst sama.><Noodistus on arvatavasti heli järgi vähemalt kontrollitud. Kas tekstiosale võiks lisada b? Parandasin viisi viite (ERA III 2, 47 (34))>', 1),
    ('ERA III 2, 47 (36)', 'ERA II 17, 123/5 (67)', NULL, NULL, 'VI 848', 1, 1, 1, NULL, NULL, 1),
    ('ERA III 2, 47 (37)', 'N', NULL, NULL, 'XIV 568', 1, 1, 1, NULL, NULL, 1),
    ('ERA III 2, 57 (48)', 'N', 'ERA, Fon. 216 c', NULL, 'VI 321', 1, 1, 1, NULL, '<Selge heli, viis noodiga sama, ülesehitus noodist veidi erinev.><Ebakorrapärane struktuur. Seda võib struktuuri järgi pidada ka refrääniliseks lauluks.>', 1),
    ('ERA III 2, 61 (53)', 'ERA II 17, 156 (94)', NULL, NULL, 'IX 367', 1, 1, 1, NULL, '<Originaalides on Mõtsa k ja Metsa k, siin tabelis aga oli Matsa küla. Mida veel?>', 1),
    ('ERA III 2, 63 (55)', 'ERA II 17, 159 (100)', NULL, NULL, 'III 411', 1, 1, 1, NULL, '<Originaalides on Mõtsa k ja Metsa k, siin tabelis aga oli Matsa küla. Mida veel? Lisasin teksti viite ja sellega seonduva.>', 1),
    ('ERA III 2, 65 (57)', 'ERA II 17, 168/9 (118)', NULL, NULL, 'VI 833', 1, 1, 1, NULL, NULL, 1),
    ('ERA III 2, 65 (58)', 'N', NULL, NULL, 'XIII 533', 1, 1, 1, NULL, NULL, 1),
    ('ERA III 2, 67 (62)', 'ERA II 5, 253/265', 'ERA, Fon. 217 d', NULL, 'V 190', 1, 1, 1, NULL, '<Suht pikk, halvasti arusaadav. Variatsioone on lisatud fonograafi järgi, seal on märkus "fonogr"><See ei ole 2-realine, vaid varieeruv 1-realine viis, läheb välja. Teksti kuulumine ei ole kindel.>', 1),
    ('ERA III 2, 69 (63)', 'ERA II 17, 170 (119)', NULL, NULL, 'VI 849', 1, 1, 1, NULL, '<Parandasin esitaja vanuse, mis oli 33.>', 1),
    ('ERA III 2, 69 (65)', 'ERA II 17, 171 (121)', NULL, NULL, 'XIII 532', 1, 1, 1, NULL, '<Lisasin esitaja vanuse>', 1),
    ('ERA III 2, 71 (67)', 'ERA II 17, 171/2 (123)', NULL, NULL, 'II 394', 1, 1, 1, NULL, NULL, 1),
    ('ERA III 2, 81 (77)', NULL, NULL, NULL, 'XIV 653', 1, 1, 1, NULL, '<Teksti viitesse oli tabelis kirjutatud ERA II 17, 199-231, samas noodi all ei olnud teksti. Viis ei meenuta regilaulu, teksti pole, võiks välja jätta. Rütm 3/8.>', 1),
    ('ERA III 2, 9 (1)', 'ERA II 17, 72/3 (35)', 'ERA, Fon 210 a', NULL, 'XIII 463', 1, 1, 1, NULL, '<Saab kuidagi aru, palju värsse.><Noodistusel on teise laulu (ERA II 17, 72/73 (36) tekst.>', 1),
    ('ERA III 2, 9 (1)', 'ERA II 17, 73 (36)', 'ERA, Fon 210 a', NULL, 'XIII 463', 1, 1, 1, NULL, '<Tekstikogus sama laul on kirjutatud eraldi salvestusest.>', 1),
    ('ERA III 2, 9 (2)', 'ERA II 17, 74/5 (37)', 'ERA, Fon. 210 b', NULL, 'VI 887', 1, 1, 1, NULL, '<Heli alguses on kaks sama laulu värssi teise viisiga (ERA III 2, 9 (1), Fon 210 a), vbl ebaõnnestunud. Siis algab see laul, üsna kattub noodiga, aga heli on pikem (7 värssi); tekst veel pikem.><Heli, noot ja tekst suht kattuvad, vbl viisivariatsioone heli järgi juurde märgitud? Siia on tabelis noodistaja märgitud, ei tea mis põhjendusel. Teksti juures variante, seega korratud mitu korda.>', 1),
    ('ERA III 3, 113 (102)', 'ERA II 30, 93 (1)', NULL, NULL, 'IV 372', 1, 1, 1, NULL, '<Lisasin teksti viite ja andmed>', 1),
    ('ERA III 3, 113 (104)', NULL, NULL, NULL, 'XIV 802', 1, 1, 1, NULL, '<See on esiteks 1-realine viis, teiseks, arvatavasti mitte regilaul, 3/4 taktimõõdus, ilma tekstita. Jätaksin välja.>', 1),
    ('ERA III 3, 117 (108)', 'N', NULL, NULL, 'IV 371', 1, 1, 1, NULL, NULL, 1),
    ('ERA III 3, 153 (149)', 'ERA II 26, 119 (8, 9)', 'ERA, Fon. 280 d', NULL, 'IV 363', 1, 1, 1, NULL, '<Selge hääl. Helis on 4 ja noodistuses 2,5 värssi, 3. värss ja laulu struktuur erinevad, tekstides 8 ja 9 kõike need värsid ja enamgi. ><Kogu noot ei saa olla salvestuse järgi (kui sealt pole midagi kadunud). Lisasin teksti viite ja teise vormi. Sellest tegin andmebaasi kirje 7.01.2020>', 1),
    ('ERA III 3, 155 (153)', 'ERA II 26, 117/9 (5)', 'ERA, Fon. 280 a', NULL, 'I 851', 1, 1, 1, NULL, '<Selge hääl. Helis on 6, noodis 2 värssi, tekstis 8. ><Lisasin teksti viite.>', 1),
    ('ERA III 3, 155 (154)', 'ERA II 2, 11 (1)', 'ERA, Fon. 280 c', NULL, 'XIV 571', 1, 1, 1, NULL, '<Keskmine, tekst arusaadav üleskirjutuse abil. Salvestus kümmekond värssi: pikem kui noodi 2 värssi, lühem kui tekst, millega osalt kattub.><Muutsin vormi ja laululiigi, lisasin teksti viite ja eesnime salvestuse põhjal. Tekst on kirjutatud 1928, kuid olemasolevates ridades kattub hästi salvestuse ja noodiga 1930. Tekstikogus järgnev pulmalaul (ERA II 2, 13 (3) on tõenäoliselt lauldud sama viisiga.>', 1),
    ('ERA III 3, 161 (158)', 'ERA II 26, 131/3 (1)', 'ERA, Fon. 281 a', NULL, 'IV 377', 1, 1, 1, NULL, '<Selge, mõnede konarustega. Ilmselt eraldi variant (u 4 värssi), mis ei kattu täpipealt noodi ega tekstiga. Tekst pikk.><Lisasin teksti viite.>', 1),
    ('ERA III 3, 193 (200)', 'N', NULL, NULL, 'VII', 1, 1, 1, NULL, '<Lisasin koha andmeid .>', 1),
    ('ERA III 3, 207 (221)', 'ERA II 26, 189/1 (191)', 'ERA, Fon. 290 a', NULL, 'uuri välja! Registris muu', 1, 1, 1, NULL, '<Selge ja pikk. Heli, noot ja tekst täpselt vastavuses><Võib olla heli järgi noodistatud. Lisasin teksti viite, muutsin vormi, funktsiooni. Ktr üle 11.05.2020>', 1),
    ('ERA III 3, 215 (230)', 'ERA II 26, 197 (7)', 'ERA, Fon. 293 c', NULL, 'XI 116', 1, 1, 1, NULL, '<Lõpupoole jääb vaiksemaks, peaaegu arusaadav.><Kirje tegin vastavalt noodile. See helisalvestus on vale, tuleks siit kustutada ja leida õige koht, samuti teha originaali märkus. Ei tea, miks just siia on Accessis märgitud noodistajaks E. Oja (mujal üldiselt dešifreerijat pole märgitud) - see heli ja noodistus ei ole mingil juhul vastavuses. Ktr üle 11.05.2020.>', 1),
    ('ERA III 3, 233 (257)', NULL, 'ERA, Fon. 297 a, b', NULL, 'IV 415', 1, 1, 1, NULL, '<Halvasti arusaadavad sõnad. a) u 15 värssi b) 4 värssi><Tõenäoliselt noodistatud kahe fonograafi salvestuse järgi.>', 1),
    ('ERA III 3, 45 (34)', 'ERA II 26, 49 (24)', NULL, NULL, 'XII 426', 1, 1, 1, NULL, '<Lisasin esitaja andmeid>', 1),
    ('ERA III 3, 49 (39)', 'ERA II 26, 51 (29)', NULL, NULL, 'XV 425', 1, 1, 1, NULL, '<Lisasin esitaja andmeid, parandasin teksti jõle > jäle (!)>', 1),
    ('ERA III 3, 51 (42)', 'ERA II 26, 59 (1)', NULL, NULL, 'I 779', 1, 1, 1, NULL, NULL, 1),
    ('ERA III 3, 55 (46)', 'ERA II 26, 62/3 (5))', NULL, NULL, '409', 1, 1, 1, NULL, '<Lisasin teksti viite, aga see on UL, seda ei võta.>', 1),
    ('ERA III 3, 57 (50)', 'ERA II 26, 51 (32)', NULL, NULL, 'VI 630', 1, 1, 1, NULL, '<See pole klassikaline 2-realine viis, on siin tinglikult, minu meelest sobiks paremini varaste vokaalžanride eraldi rühma. Lisasin esitaja andmeid.>', 1),
    ('ERA III 3, 57 (51)', NULL, NULL, NULL, 'I 889', 1, 1, 1, NULL, '<Lisasin esitaja andmeid.>', 1),
