    ('ERA III 4, 177 (10)', 'ERA II 30, 373/5 (11)', NULL, NULL, 'XII 35', 1, 1, 1, '<Retkest on kirjutanud Anu Vissel. https://www.folklore.ee/tagused/nr23/kreek.pdf>', '<Noodistuse järgi võib olla kas 2-realine varieeruv vorm või 4-realine viis, mis võib samuti olla ebakorrapärane. Tekst ei ole üleskirjutuse põhjal 4-realistes stroofides. (vrdl ERA II 30, 377/9 (11))>', 1),
    ('ERA III 4, 177 (11)', 'ERA II 30, 377/9 (13)', NULL, NULL, 'V 62', 1, 1, 1, '<Retkest on kirjutanud Anu Vissel. https://www.folklore.ee/tagused/nr23/kreek.pdf>', '<Noodistuse järgi võib olla kas 2-realine varieeruv vorm või 4-realine vorm, mis võib samuti olla ebakorrapärane. Tekst ei ole üleskirjutuse põhjal kohandatud 4-realisele viisile (s.t stroofide taoline). (vrdl ERA II 30, 377/9 (10))>', 1),
    ('ERA III 4, 189 (3)', 'ERA II 30, 399 (5)', NULL, NULL, 'XIII 319', 1, 1, 1, '<Retkest on kirjutanud Anu Vissel. https://www.folklore.ee/tagused/nr23/kreek.pdf>', '<Lisasin teksti viite ja andmed>', 1),
