    ('ERA III 4, 197 (8)', 'ERA II 30, 413 (9) / ERA III 4, 197 (8)', NULL, NULL, 'IV 85', 1, 1, 1, '<Retkest on kirjutanud Anu Vissel. https://www.folklore.ee/tagused/nr23/kreek.pdf>', '<Parandasin teksti viite (oli ERA II 30, 413 (a)), kommentaari (oli "Pruudi viis"), esitaja soo (N). Selle kirje oli kirjutanud ilma silmanägemiseta inimene....>', 1),
    ('ERA III 4, 199 (10)', 'ERA II 30, 415 (10)', NULL, NULL, 'VIII 170', 1, 1, 1, '<Retkest on kirjutanud Anu Vissel. https://www.folklore.ee/tagused/nr23/kreek.pdf>', '<Parandasin esitaja nime (Annub), lisasin andmeid>', 1),
