    ('ERA III 6, 131', 'EStk 15, 37/8 (30)', 'ERA, Fon. 336 c', NULL, 'IX 215', 1, 1, 1, NULL, NULL, NULL),
    ('ERA III 6, 133 (2)', 'ERA III 6, 133 (2)', 'ERA, Fon. 332', NULL, 'XIV 500', 1, 1, 1, '<Udo Kolk "Regiviiside varieerumisest" (1984: 63/4) - osaliselt noodistatud>', '<fonogramm katki, noodistused osalised><Lisasin andmed: esitaja, koguja jm (siin polnud isegi kuulsa Liisu Mägi nime!) põhiliseks allikaks Kolk, Udo "Regiviiside varieerumisest" 1984. Ei tea, kas Loorits noodistas fonogrammilt, Kolk küll. Otsisin teksti kõikjalt peale EÜSI kogu.>', 1),
    ('ERA III 6, 134 (5)', NULL, 'ERA, Fon. 335 a', NULL, 'XIV 728', 1, 1, 1, '<Udo Kolk "Regiviiside varieerumisest" (1984: 66) on salvestuselt osaliselt noodistanud neid värsse, mida Loorits pole noodistanud.>', '<kohati segane, 16 värssi><Lisasin andmed: esitaja, koguja jm (siin polnud isegi kuulsa Liisu Mägi nime!), põhiliseks allikaks Kolk, Udo "Regiviiside varieerumisest" 1984. Et Looritsal teksti pole ja viis on skemaatiline, siis ei tea, kas Loorits noodistas fonogrammilt. Otsisin teksti kõikjalt peale EÜSi kogu.>', 1),
    ('ERA III 6, 136 (5)', 'ERA II 10, 645 (5)', 'ERA, Fon. 313 e', NULL, 'VI 350', 1, 1, 1, NULL, '<selge, kattub noodistusega><Salvestuse järgi noodistatud või kontrollitud. Lisasin teksti viite. Tekst kirjutatud aasta varem, pisikeste erinevustega.>', 1),
    ('ERA III 6, 139 (2)', 'N', 'ERA, Fon. 329 b', NULL, NULL, 1, 1, 1, NULL, '<selge, rohkem sõnu kui noodis><Setu 9-sibiline värss (ühe lisasilbiga)>', 1),
    ('ERA III 6, 163 (1)', 'ERA III 6, 163 (1)', NULL, NULL, 'VII', 1, 1, 1, NULL, NULL, 1),
    ('ERA III 6, 18/19 (13)', 'ERA II 30, 59 (41)', 'ERA, Fon. 305 g', NULL, 'II 339', 1, 1, 1, NULL, '<keskmiselt arusaadav, noodistus vastab salvestusele, kuid selles on häälikute ja helikõrguse erinevusi - noodistuse vigu? Laul jääb ilmselt pooleli, tekst on pikem.><Parandasin viisi viite, lisasin teksti viite jm.>', 1),
    ('ERA III 6, 184 (6)', 'ERA II 35, 161 (1)', 'ERA, Fon. 339 d', NULL, 'XII 424', 1, 1, 1, NULL, '<Selge, kattub noodi ja tekstiga.><Võib olla salvestuse järgi noodistatud. Lisasin salvestuse viite.>', 1),
    ('ERA III 6, 185 (12)', 'ERA III 6, 185 (12) / ERA II 173/4 (1)', 'ERA, Fon. 339 g', NULL, 'XIII 232', 1, 1, 1, NULL, '<kahisev,  enam-vähem arusaadav, kõik värsid ei kattu noodistusega><Võib olla noodistust salvestuse järgi kontrollitud, kuid mõlemas on ka erinevaid värsse. Pikk tekst. Lisasin salvestuse ja teksti viite. Teksti juures on vana heliviide.>', 1),
    ('ERA III 6, 186 (14)', 'ERA II 35, 175/6 (2)', 'ERA, Fon. 340 b', NULL, 'XII 423', 1, 1, 1, NULL, '<selge, kattub üldjoontes noodiga><Võib olla salvestuse järgi noodistatud. Lisasin salvestuse viite. Teksti juures on vana heliviide.>', 1),
    ('ERA III 6, 187 (18)', 'ERA II 35, 182/7 (5)', 'ERA, Fon 340 a', NULL, '411', 1, 1, 1, NULL, '<selge, 4 värssi><Laul algab eeltaktiga ja lõppeb 7-silbilise reaga, näeb UL moodi välja. Noodistus vastab pigem 3.-4. värsile. Lisasin heli ja teksti viite.>', 1),
    ('ERA III 6, 188 (21)', 'ERA II 35, 191 (9)', 'ERA, Fon 340 e', NULL, 'IX 360', 1, 1, 1, NULL, '<helisalvestus on tehtud teise variandi järgi, selge><Noodistus erineb salvestusest, tehtud ilmselt salvestamata esituse või mõlema esituse põhjal. Lisasin heli viite.>', 1),
    ('ERA III 6, 189 (23)', 'ERA II 35, 197 (2)', 'ERA, Fon. 341 b', NULL, 'VI 383', 1, 1, 1, NULL, '<heli kattub noodi ja tekstiga, selge><Lisasin heli, teksti viited.>', 1),
    ('ERA III 6, 199/200 (47)', 'ERA III 6, 199/200 (47)', 'ERA, Fon. 345 f', NULL, 'XIII 566', 1, 1, 1, NULL, '<selge, vastab täpselt noodile><Tõenäoliselt noodistatud salvestuse järgi.>', 1),
    ('ERA III 6, 206 (55)', NULL, NULL, NULL, 'X 295', 1, 1, 1, NULL, '<Üks 11-silbiline värss, 9-11 positsiooni - see pole 2-realine viis.>', 1),
    ('ERA III 6, 209 (63)', 'ERA II 35, 436 (15)', NULL, NULL, 'XV 291', 1, 1, 1, NULL, '<Viisis 12 positsiooni, värsialguse kordus. Pole 2-realine viis.>', 1),
    ('ERA III 6, 21 (18)', 'ERA II 30, 32 (8)', NULL, NULL, 'I 731', 1, 1, 1, NULL, '<Lisasin andmeid teksti kogumise, lauliku kohta>', 1),
    ('ERA III 6, 21 (19)', 'ERA II 30, 31 (7)', NULL, NULL, 'I 730', 1, 1, 1, NULL, '<Lisasin andmeid teksti kogumise, lauliku kohta>', 1),
    ('ERA III 6, 210 (68)', 'ERA II 35, 231/2 (1)', NULL, NULL, 'XI 187', 1, 1, 1, NULL, '<Lisasin teksti viite. Teksti juures antud viisi nr ei kehti, sest viiside numbreid on hiljem muudetud.>', 1),
    ('ERA III 6, 211 (74, 75)', 'N', NULL, NULL, '63', 1, 1, 1, NULL, NULL, 1),
    ('ERA III 6, 214 (83)', 'N', NULL, NULL, 'X 256', 1, 1, 1, NULL, NULL, 1),
    ('ERA III 6, 216 (92)', 'ERA II 35, 552 (2)', 'ERA, Fon. 346 b', NULL, NULL, 1, 1, 1, NULL, '<See on 4-realine viis või 2-realine refrääniga viis, ei kuulu siia.>', 1),
    ('ERA III 6, 22 (21)', 'ERA II 30, 62 (2) / ERA III 6, 22 (21)', 'ERA, Fon 306 a', NULL, 'XIII 390', 1, 1, 1, NULL, '<Selge, pisiasjades erineb noodist ja 4 värssi pikem, tekstiga ühepikkune. ><Lisasin teksti ja heli viite, andmeid teksti kogumise (koguja nimi), lauliku kohta (sugu oli märgitud tabelis M? - aga "eit"!)>', 1),
    ('ERA III 6, 227 (114)', 'ERA II 35, 593/4 (8)', 'ERA, Fon. 349 b', NULL, 'XII 420', 1, 1, 1, NULL, '<Algus segane, 4 värssi, kattub noodiga><Värsi algust korratakse, 12 postisiooni, see pole 2-realine viis>', 1),
    ('ERA III 6, 229 (121)', 'N', NULL, NULL, '81', 1, 1, 1, NULL, '<Parandasin küla nime (Kõnnu)>', 1),
    ('ERA III 6, 23 (23)', 'ERA II 30, 108 (1)', NULL, NULL, 'I 579', 1, 1, 1, NULL, '<Lisasin andmeid teksti kogumise kohta (koguja nimi, aasta)>', 1),
    ('ERA III 6, 23 (24)', 'ERA II 30, 111 (7)', NULL, NULL, 'II 357', 1, 1, 1, NULL, '<Lisasin teksti viite, andmeid teksti kogumise (koguja nimi), lauliku kohta.>', 1),
    ('ERA III 6, 232 (130)', 'ERA II 35, 507 (8) ?', NULL, NULL, 'XIV 659', 1, 1, 1, NULL, '<Lisasin lauliku sünnikoha, otsisin vastavat teksti.>', 1),
    ('ERA III 6, 238 (154)', 'ERA II 36, 110 (9)', 'ERA, Fon. 350 c', NULL, 'I 888', 1, 1, 1, NULL, '<Vaikne, selge, kõnelähedane esitus, kattub üldjoontes noodistuse ja tekstiga. Noodis 2 värssi, mujal 4.><Lisasin teksti viite ja esitaja andmeid tekstikogust. Tekst on kirjutatud fonogrammi järgi, viisi võib olla kontrollitud.>', 1),
    ('ERA III 6, 247 (163)', 'ERA II 36, 219/20 (1)', 'ERA, Fon. 351 c', NULL, 'IX 284', 1, 1, 1, NULL, '<Alguses ja hiljem kohati arusaamatu, tempo muutub. Pikkuselt vastab tekstile.><Parandasin esitaja nime Latim??. Tekst on kirjutatud fonogrammi järgi, viis võib-olla ka.>', 1),
    ('ERA III 6, 247 (165)', 'ERA II 36, 222/3 (5)', 'ERA, Fon. 351 e', NULL, 'XII 419', 1, 1, 1, NULL, '<Segane, müraga, tempo muutub. 8 värssi, noodistus 4 värssi, tekst pikem.><Lisasin märkusi, andmeid. Tekst on osalt kirjutatud fonogrammi järgi (F.), osalt dikteeritud (D.).>', 1),
    ('ERA III 6, 25 (29)', 'ERA II 30, 145/6 (2 a) / ERA III 6, 25 (29)', 'ERA, Fon. 306 b1', NULL, 'II 195', 1, 1, 1, '<VK VIII>', '<Selge. Füüsiliselt on üks salvestus (306 b) ja üks tekst (145/6 (2), mis ei ole jagatud, kuid nad vastavad kahele eri noodile ERA III 6, 25 (29, 30).><Lisasin teksti viite, noodistaja ja litereerija andmed oli tabelisse kirjutanud ilmselt Edna Tuvi. Tekst on kirjutatud vähemalt kahe esituse põhjal.>', 1),
    ('ERA III 6, 251 (180)', 'ERA II 36, 233/4 (1)', 'ERA, Fon. 352 b', NULL, 'IX 248', 1, 1, 1, NULL, '<Enam-vähem. Tekst on kirjutatud teise variandi järgi.><Parandasin esitaja Latui??. Noodistuse juurde on originaalis märgitud vale esitaja, samuti on viga nootide ja fonogrammide registris - Juhan Latik. Noot vastab fonogrammile ja sealt kuuleb selgesti, et naine laulab, ja sama variandi tekst on tekstikogus naise nimega.>', 1),
    ('ERA III 6, 26 (31)', 'ERA II 30, 145 (1)', 'ERA, Fon. 306 c', NULL, '378', 1, 1, 1, '<VK VIII ?>', '<Kena, veidi erineb noodist, tekstiga kattub.><VÕib olla ka 4-realine viis. Pigem riimiline laul, Noot on tõeneäoliselt tehtud välitöödel. Lisasin teksti viite.>', 1),
    ('ERA III 6, 26 (34)', 'ERA II 30, 150 (9)', 'ERA, Fon. 306 f', NULL, NULL, 1, 1, 1, '<VK VIII>', '<Kena, kattub noodi ja tekstiga.><Muutsin vormi tähistust (oli 1x2 ?) heli järgi. Vorm on noodis ja helis veidi erinev.>', 1),
    ('ERA III 6, 263 (11)', NULL, NULL, NULL, 'IV 358', 1, 1, 1, NULL, NULL, 1),
    ('ERA III 6, 275 (2)', 'E, StK 3, 35 (11)', NULL, NULL, 'IV 410', 1, 1, 1, NULL, '<Viis on üles kirjutatud 1923, saadetud 1933. Lisasin teksti viite ja andmed.>', 1),
    ('ERA III 6, 275 (6)', 'E, StK 3, 42 (18)', NULL, NULL, '139', 1, 1, 1, NULL, '<Viis on üles kirjutatud 1923, saadetud 1933. Lisasin teksti viite ja andmed.>', 1),
    ('ERA III 6, 276 (9)', 'E, StK 3, 57/58 (2)', NULL, NULL, 'V 104', 1, 1, 1, NULL, '<Viis on üles kirjutatud 1923, saadetud 1933. Laulja vanuses on vastuolu. Lisasin teksti viite ja andmed.>', 1),
    ('ERA III 6, 34 (44)', 'ERA II 30, 111 (7)', 'ERA, Fon. 310 d', NULL, '370', 1, 1, 1, NULL, '<Lisasin teksti viite. See ei ole regilaul, nt 1. värss 6 silpi, 2. 5 silpi, hiljem tuleb värsse:" Vaivab mind siin kurptus, nutan alati.">', 1),
    ('ERA III 6, 82 (3)', 'ERA III 6, 82 (3) / ERA II 29, 281 V.A; 283 V.B', 'ERA, Fon. 316 a', NULL, 'VIII 469', 1, 1, 1, NULL, '<Peaaegu arusaadav, algus ja lõpp segased, noot vastav><Noodistatud (või kontrollitud) on salvestuse järele, detailides on suur kokkulangevus. Originaalis ei ole eristatud kahe üleskirjutaja tekste samast esitusest ega nende nimesid. Tegin ise tähistused: A Viidalepp, B Ariste.>', 1),
    ('ERA III 6, 83 (4)', 'ERA II 29, 285 VI.A (a, b); 287 VI.B (a, b)', 'ERA, Fon. 316 b', NULL, 'IX 219', 1, 1, 1, NULL, '<Digi- ega magnetofonikoopiat pole: "lindil pole" (reg)><Noodistas Leichter arvatavasti salvestuse abil. Kaks tekstivarianti, kummalgi a ja b osa. Originaalis ei ole eristatud kahe üleskirjutaja tekste samast esitusest ega nende nimesid. Tegin ise tähistused: A Viidalepp, B Ariste. Parandasin viisi viite, ERA III 6, 83 (24), lisasin heli puudumise märkuse.>', 1),
    ('ERA III 6, 86 (7)', 'ERA II 29, 297 IX.A, 299/301 IX.B', 'ERA, Fon. 316 e', NULL, 'VII 145', 1, 1, 1, NULL, '<Peaaegu arusaadav, viis ei vasta täpselt noodile ja on värsikese pikem, tekst veel pikem.><Noodistas Leichter, ta võis kasutada salvestuse abi. Lisasin teksti viite. Originaalis ei ole eristatud kahe üleskirjutaja tekste samast esitusest ega nende nimesid. Tegin ise tähistused: A Viidalepp, B Ariste.>', 1),
    ('ERA III 7, 101 (40)', 'N', NULL, NULL, 'VI 344', 1, 1, 1, NULL, NULL, 1),
    ('ERA III 7, 102 (42)', 'ERA II 56, 194/5 (3) / N', 'ERA, Fon. 380 b', NULL, 'VI 260', 1, 1, 1, NULL, '<Peaaegu arusaadav, viis vastab üldjoontes noodile, pisiasjades erinev - ja helirida on erinev!><Lisasin teksti viite. Noot ja tekst kattuvad, on ehk üks esitus, helisalvestus väga sarnane teine esitus.>', 1),
    ('ERA III 7, 102 (42)', NULL, NULL, NULL, '1133', 1, 1, 1, NULL, '<See laul on andmebaasis topelt, dublikaat tuleks kustutada.>', 1),
    ('ERA III 7, 122/4 (2)', 'ERA III 7, 122/4 (2) / ERA II 115, 115/6 (3)', 'ERA, Fon. 439 b', NULL, 'IV 367', 1, 1, 1, NULL, '<Selge, vastab detailides noodistusele.><Ilmselt noodistatud salvestuselt, tekst kirjutatud teise esitusvariandi järgi. Lisasin teksti viite.>', 1),
    ('ERA III 7, 132/3 (11)', 'ERA III 7, 132/3 (11) / ERA II 115, 138/9 (32)', 'ERA, Fon. 442 c', NULL, 'IV 416', 1, 1, 1, NULL, '<Kahisev, vastab detailides noodistusele.><Ilmselt noodistatud salvestuselt. Lisasin teksti viite.>', 1),
    ('ERA III 7, 139/40 (18)', 'ERA III 7, 139/40 (18) / ERA II 115, 161 (5)', 'ERA, Fon. 444 d', NULL, 'IV 417', 1, 1, 1, NULL, '<Kahisev, vastab detailides noodistusele.><Ilmselt noodistatud salvestuselt. Lisasin teksti viite.>', 1),
    ('ERA III 7, 145 (25)', 'ERA II 115, 183 (1)', NULL, NULL, 'XIII 279', 1, 1, 1, NULL, '<Lisasin teksti viite.>', 1),
    ('ERA III 7, 152 (30)', 'ERA II 115, 185 (1)', 'ERA, Fon. 448 a', NULL, 'X 128', 1, 1, 1, NULL, '<Halvasti arusaadav, tempo muutub,  noodist pikem, 10 värssi><Vbl on Tampere pikemast noodistusest loobunud, kui heli oli juba siis halva kvaliteediga. Pealegi on viis vähe varieeruv. Lisasin teksti viite.>', 1),
    ('ERA III 7, 152/3 (32)', 'ERA III 7, 152/3 (32) / ERA II 115, 187 (4)', 'ERA, Fon. 449 a', NULL, 'XI114', 1, 1, 1, NULL, '<Arusaadav, vastab detailides noodistusele><Ilmselt noodistatud salvestuselt. Lisasin teksti viite.>', 1),
    ('ERA III 7, 167/8 (7)', 'ERA III 7, 167/8 (7) / ERA II 115, 244/6 (7)', 'ERA, Fon. 454 c', NULL, 'VII 118', 1, 1, 1, '<Tampere ERlV III: 42-44>', '<Arusaadav, vastab detailides noodistusele><Kindlasti noodistatud salvestuselt, välitööde noodistust ei ole. Lisasin teksti viite.>', 1),
    ('ERA III 7, 173 (14)', 'ERA III 7, 173 (14)', 'ERA, Fon. 456 c', NULL, 'XII 358-359', 1, 1, 1, NULL, '<Selge, vastab detailides noodistusele.><Kindlasti noodistatud salvestuselt, välitööde noodistust ei ole.>', 1),
    ('ERA III 7, 303 (18)', 'N', NULL, NULL, 'I 885', 1, 1, 1, NULL, '<Gerda Laugaste isa on Karl Kink 1866-1946 (Geni). Siin oli viites vale 18a. Parandasin ka "juljused" asemele "kuljused". :-) Tekst on pigem nagu loitsu kõla imitatsioon, lisasin tekstitüübi.>', 1),
    ('ERA III 7, 305 (22)', 'N', NULL, NULL, 'VII 150', 1, 1, 1, NULL, '<See ei ole korrapärane 2-realine viis, see on 1-realine või isegi poolerealine viis erandliku lõpuosaga. Siin on ka pikk refrään. Ma ei võtaks 2-realiste hulka.>', 1),
    ('ERA III 7, 313 (1)', 'ERA III 7, 313 (1)', NULL, NULL, 'I 588', 1, 1, 1, NULL, '<Koguja nimi on ebatavaline, kas see on õige? Kust tuli kihelkonna nimi?>', 1),
    ('ERA III 7, 313 (2)', 'ERA III 7, 313 (1)', NULL, NULL, 'I 589', 1, 1, 1, NULL, '<Lauluteksti ei ole, kuid viis praktiliselt kattub eelmisega ja ilmselt on mõeldud ka, et eelmise tekst sobib. Kust tuli kihelkonna nimi?>', 1),
    ('ERA III 7, 55 (22)', 'ERA, II 56, 91/2 (2)', 'ERA, Fon. 360 c', NULL, 'XIII 286', 1, 1, 1, NULL, '<Vaikne, kahiseb, tekst suht arusaamatu. Noot on helist lühem lühem, tekst pikem. ><Lisasin heli ja teksti viite, noodi juures on vana fonogramminumber.>', 1),
    ('ERA III 7, 64 (46)', 'ERA II 56, 43/5 (1)', 'ERA, Fon. 365 b', NULL, 'XII 352', 1, 1, 1, NULL, '<Kahiseb, kostab halvasti. Noot on helist lühem, tekst pikem. Tekst on kirjutatud sõltumatult, teise esituse järgi. ><Lisasin teksti viite, laulutüübi, noodi juures on vana fonogramminumber.>', 1),
    ('ERA III 7, 66 (51)', 'ERA II 56, 419/20 (10)', 'ERA, Fon. 367 d', NULL, 'VIII 268', 1, 1, 1, NULL, '<Kahiseb, peaaegu arusaadav. Noot on helist lühem, tekst pikem.><Parandasin valla: Väike-Vändra. Noodi juures on vana fonogramminumber.>', 1),
    ('ERA III 7, 66 (52)', 'ERA III 7, 66 (52) / ERA II 56, 420/1 (11)', 'ERA, Fon 371 b', NULL, 'XIII 519', 1, 1, 1, NULL, '<Kahiseb, kostab halvasti. Noodistatud on palju variatsioone, aga mitte kogu salvestust.><Noodistus tehtud salvestuse põhjal. Noodi juures on vana fonogramminumber. Lisasin heli viite.>', 1),
    ('ERA III 7, 74/5 (4)', 'ERA III 7, 74/5 (4) / ERA II 56, 309/10 (68)', 'ERA, Fon. 390 c', NULL, 'II 364', 1, 1, 1, NULL, '<Vaikne, arusaadav, vastab detailides noodile.><Noodistus tehtud salvestuse põhjal. Noodi juures on vana fonogramminumber.>', 1),
    ('ERA III 7, 76/7 (7)', 'ERA III 7, 76/7 (7) / ERA II 56, 288/9 (6)', 'ERA, Fon. 390 d', NULL, 'VII', 1, 1, 1, NULL, '<Vaikne, arusaadav, vastab detailides noodile.><Noodistus tehtud salvestuse põhjal. Noodi juures on vana fonogramminumber. Lisasin andmeid.>', 1),
    ('ERA III 7, 81/3 (13)', 'ERA III 7, 81/3 (13) / ERA II 56, 366/9 (30)', 'ERA, Fon. 387 a', NULL, 'XIII 205', 1, 1, 1, NULL, '<Selge, vastab detailides noodile. Pikem tekst tekstikogus.><Lisasin heli viite. Noodistus tehtud salvestuse põhjal. Noodi juures on vana fonogramminumber.>', 1),
    ('ERA III 7, 83/5 (14)', 'ERA III 7, 83/5 (14) / ERA II 56, 355 (19)', 'ERA, Fon. 387 b', NULL, 'XI 435', 1, 1, 1, NULL, '<Selge, vastab detailides noodile. Tekst arvatavasti teise esituse järgi.><Noodistus tehtud salvestuse põhjal. Noodi juures on vana fonogramminumber.>', 1),
    ('ERA III 7, 87/8 (18)', 'ERA III 7, 87/8 (18) / ERA II 56, 238/9 (3)', 'ERA, Fon. 389 b', NULL, 'XI 139', 1, 1, 1, NULL, '<Praktiliselt kuuldamatu, kuid ilmselt noodistatud. Tekst arvatavasti teise esituse järgi.><Noodistus arvatavasti tehtud salvestuse põhjal. Noodi juures on vana fonogramminumber.>', 1),
    ('ERA III 7, 88/9 (19)', 'ERA III 7, 88/9 (19) / ERA II 56, 247/8 (39)', 'ERA, Fon. 389 c', NULL, 'XI 72', 1, 1, 1, NULL, '<Vaikne, arusaadav, vastab noodile ja tekstile.><Noodistus tehtud salvestuse põhjal. Noodi juures on vana fonogramminumber.>', 1),
    ('ERA III 7, 89 (20)', 'ERA II 56, 267/8 (109)', NULL, NULL, 'XIII 315', 1, 1, 1, NULL, NULL, 1),
    ('ERA III 7, 89 (21)', 'ERA II 56, 248/9 (41)', NULL, NULL, 'XIII 476', 1, 1, 1, NULL, NULL, 1),
    ('ERA III 7, 90 (22)', 'ERA III 7, 90 (22) / ERA II 56, 264/5 (99)', NULL, NULL, 'VI 330', 1, 1, 1, NULL, '<Parandasin nime Anmann; lisasin teksti viite.>', 1),
    ('ERA III 7, 91 (24)', 'ERA III 7, 91 (24) / ERA II 56, 271/2 (2)', 'ERA, Fon. 388 a', NULL, 'VII', 1, 1, 1, NULL, '<Selge, vastab detailides noodistusele.><Noodistus tehtud salvestuse põhjal. Noodi juures on vana fonogramminumber.>', 1),
    ('ERA III 7, 92/3 (25)', 'ERA III 7, 92/3 (25) / ERA II 56, 272/3 (3)', 'ERA, Fon. 388 b', NULL, 'IV 88', 1, 1, 1, NULL, '<Selge, vastab detailides noodistusele ja tekstile.><Lisasin teksti viite. Noodistus tehtud salvestuse põhjal. Noodi juures on vana fonogramminumber.>', 1),
    ('ERA III 7, 93 (26)', 'ERA II 56, 273 (4)', 'ERA, Fon. 388 c', NULL, 'II 354', 1, 1, 1, NULL, '<Selge, noodist pikem,  vastab tekstile (5 värssi)><Noot (1 värss) võib olla tehtud salvestuse põhjal. Noodi juures on vana fonogramminumber.>', 1),
    ('ERA III 7, 94/5 (29)', 'ERA II 56, 278/9 (2)', NULL, NULL, 'IX 459', 1, 1, 1, NULL, '<Tekst ja viis eri isikutelt.>', 1),
    ('ERA III 7, 96 (31)', 'ERA II 56, 281/3 (5)', NULL, NULL, 'XI 206', 1, 1, 1, NULL, '<Täpsustasin stroofi vormi, see oli AB. Siin on formaalselt sama palju noote kui 2-realises viisis, kuid tegelikult on värss ja viis teistsuguse struktuuriga.>', 1),
    (NULL, 'ERA II 172, 18/9 (3)', 'ERA, Pl. 19 A1', NULL, 'XV 459', 1, 1, 1, NULL, '<Selge ja ilus><Tõstsin viisi viite originaali kohalt noodistuste hulka, sest noodistus on helisalvestuse transkriptsioon. Noodistusest on mustand ja täpsustatud tekstiga (?) ümberkirjutus (RKM III 4). Kaardil viis vastab mustandile. Tekst ja heli ei kattu täpselt, on jäädvustatud eri esituste järgi. Muutsin laululiigi, lisasin laulutüübi. 21.02.2019>', 1),
    (NULL, 'ERA II 172, 28/9 (13)', 'ERA, Pl. 19 A3', NULL, 'XV 461', 1, 1, 1, NULL, '<Selge ja ilus><Tõstsin viisi viite originaali kohalt noodistuste hulka, sest noodistus on helisalvestuse transkriptsioon. Noodistusest on mustand ja täpsustatud tekstiga (?) ümberkirjutus (RKM III 4). Kaardil viis vastab mustandile, aga heliga võrreldes väikseid vigu. Tekst ja heli ei kattu täpselt, on jäädvustatud eri esituste järgi. Lisasin laulutüübi. Muutsin laululiigi. 21.02.2019>', 1),
    (NULL, 'ERA II 172, 39/40 (22)', 'ERA, Pl. 19 B1', NULL, 'XV 462', 1, 1, 1, NULL, '<Selge ja ilus><Tõstsin viisi viite originaali kohalt noodistuste hulka, sest noodistus on helisalvestuse transkriptsioon. Noodistusest on mustand ja täpsustatud tekstiga (?) ümberkirjutus (RKM III 4). Kaart vastab mustandile, hea noodistus, pisikesi ebatäpsusi. Tekst ja heli ei kattu täpselt, on jäädvustatud eri esituste järgi. Lisasin laulutüübi. Muutsin laululiigi. 21.02.2019>', 1),
    (NULL, 'ERA II 172, 40 (23)', 'ERA, Pl. 19 B2', NULL, 'XV 463', 1, 1, 1, NULL, '<Selge ja ilus><Tõstsin viisi viite originaali kohalt noodistuste hulka, sest noodistus on helisalvestuse transkriptsioon. Noodistusest on mustand ja täpsustatud teksitga (?) ümberkirjutus (RKM III 4). Kaart vastab mustandile, hea noodistus, pisikesi ebatäpsusi. Tekst ja heli üsna kattuvad, aga on jäädvustatud eraldi. Muutsin laululiigi, lisasin laulutüübi. 21.02.2019>', 1),
    (NULL, 'ERA II 172, 29/30 (14)', 'ERA, Pl. 19 B3', NULL, 'XV 464', 1, 1, 1, NULL, '<Selge ja ilus><Tõstsin viisi viite originaali kohalt noodistuste hulka, sest noodistus on helisalvestuse transkriptsioon. Noodistusest on mustand, täpsustatud tekstiga (?) ümberkirjutus (RKM III 4) ja kartoteegikaart. Kaart vastab mustandile, aga heliga võrreldes väikseid ebatäpsusi.Tekst ja heli ei kattu täpselt, on jäädvustatud eri esituste järgi. Muutsin laululiigi, lisasin laulutüübi. 21.02.2019>', 1),
    (NULL, NULL, 'ERA, Pl. 20 B3', NULL, 'XV 470', 1, 1, 1, NULL, '<Selge ja ilus><Tõstsin viisi viite originaali kohalt noodistuste hulka, sest noodistus on helisalvestuse transkriptsioon. Noodistusest on mustand ja täpsustatud tekstiga (?) ümberkirjutus (RKM III 4). Kaart vastab mustandile, üsna hea noodistus. Lisasin laulutüübi. 21.02.2019>', 1),
    (NULL, 'ERA II 39, 87 (2)', 'ERA, Pl. 21 B1', NULL, 'XV 472', 1, 1, 1, NULL, '<Selge ja ilus><Tõstsin viisi viite originaali kohalt noodistuste hulka, sest noodistus on helisalvestuse transkriptsioon. Noodistusest on mustand ja täpsustatud tekstiga (?) ümberkirjutus (RKM III 4.) Kaart vastab mustandile, aga heliga võrreldes väikseid vigu. Tekst on kogutud 5 a varem, aga peaaegu kattub heliga. Muutsin laululiigi, lisasin laulutüübi. 21.02.2019>', 1),
    (NULL, NULL, 'ERA, Pl. 21 B4', NULL, 'XV 474', 1, 1, 1, NULL, '<Selge ja ilus><Tõstsin viisi viite originaali kohalt noodistuste hulka, sest noodistus on helisalvestuse transkriptsioon. Noodistusest on mustand ja täpsustatud tekstiga (?) ümberkirjutus (RKM III 4). Teksti otsingutest: ERA II 132, 30-67 POLE; 115 (11-23, 113-158) KATKI, VAATAMATA; 102 (36/7) POLE, 23 (259/61) POLE 21.02.2019.>', 1),
    (NULL, NULL, 'ERA, Pl. 24 A1', NULL, 'XV 475', 1, 1, 1, NULL, '<Selge ja ilus><Tõstsin viisi viite originaali kohalt noodistuste hulka, sest noodistus on helisalvestuse transkriptsioon. Noodistusest on mustand ja täpsustatud tekstiga (?) ümberkirjutus (RKM III 4). 21.02.2019>', 1),
    (NULL, NULL, 'ERA, Pl. 28 A2', NULL, 'XV 486', 1, 1, 1, NULL, '<Selge ja ilus><Tõstsin viisi viite originaali kohalt noodistuste hulka, sest noodistus on helisalvestuse transkriptsioon. Noodistusest on mustand ja ümberkirjutus. Parandasin viisi vormi, laululiigi (oli lüürika). Viis on varieeruv 1-realine, ei kuulu siia tabelisse. 21.02.2019>', 1),
    (NULL, NULL, 'ERA, Pl. 28 A3', NULL, 'XV 487', 1, 1, 1, NULL, '<Selge ja ilus><Tõstsin viisi viite originaali kohalt noodistuste hulka, sest noodistus on helisalvestuse transkriptsioon. Noodistusest on mustand ja ümberkirjutus (RKM III 4). Parandasin viisi vormi, laululiigi (oli lüürika). 21.02.2019>', 1),
    (NULL, NULL, 'ERA, Pl. 29 A1', NULL, 'XV 490', 1, 1, 1, NULL, '<Selge ja väga-väga ilus><Tõstsin viisi ja teksti viited originaalide kohalt noodistuste hulka. Noodistuseks märgitud ERA, Pl. 29 A1 on helisalvestuse transkriptsioon, teksti viiteks märgitud RKM III 4, 53/55 (1) on eelneva ümberkirjutus, mille nootides on tehtud mõned vead; teksti on vbl parandatud (ei võrrelnud.) 21.02.2019>', 1),
    ('SKS, Lähteenkorva nr. 354', 'SKS, Lähteenkorva nr. 354', NULL, NULL, 'VI 322', 1, 1, 1, '<ERv 113 (850)>', '<Käsikirja koopia on peaaegu kustunud. (Andmed olid sisestatud Launise raamatu järgi, kus oli märgitud khk, 1 värss ja ühtlustatud esitus E+K.)>', 1),
    ('SKS, Lähteenkorva nr. 239', 'N', NULL, NULL, 'XV 239', 1, 1, 1, '<ERv 156 (1160)>', '<(Andmed olid sisestatud raamatu järgi, kus oli khk, 1 värss ja ühtlustatud esitus E+K.)>', 1),
    ('SKS, Lähteenkorva nr. 355', 'SKS, Lähteenkorva nr. 355', NULL, NULL, 'XV 238', 1, 1, 1, '<ERv 157 (1172)>', '<(Andmed olid sisestatud raamatu järgi, kus oli khk, 1 värss ja ühtlustatud esitus E+K.)>', 1),
    ('SKS, Lähteenkorva nr. 315', NULL, NULL, NULL, 'XV 237', 1, 1, 1, '<ERv 161 (1201)>', '<Andmed olid sisestatud raamatu järgi, kus oli khk, 1 värss ja ühtlustatud esitus E+K.>', 1),
    ('SKS, Lähteenkorva nr. 280', NULL, NULL, NULL, 'XV 236', 1, 1, 1, '<ERv 168 (1250)>', NULL, NULL),
    ('SKS, Lähteenkorva nr. 314', NULL, NULL, NULL, 'XV 235', 1, 1, 1, '<ERv 169 (1257)>', '<Andmed olid sisestatud raamatu järgi, kus oli khk, 1 värss ja ühtlustatud esitus E+K. Andmebaasis oli märgitud esitus E+K - see võib olla raamatust (autori lisatud?), käsikirjast ei leia.>', 1),
    ('SKS, Lähteenkorva nr. 328', NULL, NULL, NULL, 'XV 234', 1, 1, 1, '<ERv 176 (1311)>', '<Andmebaasis oli märgitud esitus E+K - see võib olla raamatust (autori lisatud?), käsikirjast ei leia.>', 1),
    ('SKS, Lähteenkorva nr. 320', NULL, NULL, NULL, 'VI 238 , VI 51 järel', 1, 1, 1, '<ERV 177 (1320>', '<Andmebaasis oli märgitud esitus E+K - see võib olla raamatust (autori lisatud?), käsikirjast ei leia. LISADA 1-REALISTESSE!!!>', 1),
    ('SKS, Lähteenkorva nr. 266', NULL, NULL, NULL, 'XV 271', 1, 1, 1, '<ERv 181 (1348)>', '<Andmebaasis oli märgitud esitus E+K - see võib olla raamatust (autori lisatud?), käsikirjast ei leia.>', 1),
    ('SKS, Lähteenkorva nr. 357', 'SKS, Lähteenkorva nr. 357 a, b', NULL, NULL, 'XV 233', 1, 1, 1, '<ERv 181 (1351)>', '<On noodialune tekst ja veel üks tekst, tähistasin neid siin a ja b, käsikirjas neid tähti pole. Andmebaasis oli märgitud esitus E+K - see võib olla raamatust (Launise lisatud?), käsikirjast ei leia.>', 1),
