    ('EÜS IX 1279 (20/21)', 'N', 'ERA, Fon. 003 b', NULL, 'XIII 275', 1, 1, 1, NULL, '<Helisalvestusel sõnad arusaamatud, viis ei kattu täpselt noodiga. EÜS IX 1279 (20) vastab helisalvestuse osale ja on tekstiga, (21) on aga viisi jätk, mida salvestusel ei ole ja see on ilma tekstita. ><Lisasin heli viite. Noodistus on pikem kui helisalvestus ja ei kattu täpselt, seetõttu ei pruugi olla heli järgi noodistatud. Salvestus võis, aga ei pruukinud olla abiks noodi kirjutamisel. Esitaja elukoht oli enne märgitud Urvaste khk, Lutsa küla. Originaalis näen "sünd. Lutsa talus". Vbl elabki ta seal, aga seda pole otseselt öeldud.>', 1),
    ('EÜS IX 1279 (24)', NULL, 'ERA, Fon. 003 d', NULL, 'VIII 337', 1, 1, 1, NULL, '<Elukoht oli enne märgitud Urvaste khk, Lutsa küla. Originaalis näen "sünd. Lutsa talus". Vbl elabki ta seal, aga seda pole otseselt öeldud.>', 1),
    ('EÜS IX 1280 (28)', NULL, NULL, NULL, 'XI 152', 1, 1, 1, NULL, '<Elukoht oli enne märgitud Urvaste khk, Lutsa küla. Originaalis näen "sünd. Lutsa talus". Vbl elabki ta seal, aga seda pole otseselt öeldud.>', 1),
    ('EÜS IX 1281 (31)', 'EYÜ IX 12810/1, 1299', 'ERA, Fon. 005 b', NULL, 'IV 374', 1, 1, 1, NULL, '<Teksti viide pole kindel. Elukoht oli märgitud Hargla khk, aga see on sünnikoht (laulude õppimise koht?), Vana-Antsla vald ei ole Hargla khk. Noodistajat polnud, kuid panin Väisänen nagu teistelegi.>', 1),
    ('EÜS IX 1291 (65)', NULL, NULL, NULL, 'XIII 270', 1, 1, 1, NULL, NULL, NULL),
    ('EÜS IX 1292 (72)', 'N', 'ERA, Fon. 010 b', NULL, 'X 20', 1, 1, 1, NULL, '<Elukoht oli märgitud: Sangaste v.>Vana-Antsla v.>', 1),
    ('EÜS IX 1293 (76)', NULL, 'ERA, Fon. 010 e', NULL, '80', 1, 1, 1, NULL, NULL, 1),
    ('EÜS IX 1294 (79)', NULL, 'ERA, Fon. 011 a', NULL, 'XIV 559', 1, 1, 1, NULL, '<Märkisin sama valla ka sünnikohana, sest seda oli eraldi mainitud.>', 1),
    ('EÜS IX 1294 (79)', 'pd.', NULL, NULL, 'XIII 273', 1, 1, 1, NULL, NULL, NULL),
    ('EÜS IX 1295 (85)', NULL, 'ERA, Fon. 014 f', NULL, '77', 1, 1, 1, NULL, '<Märkisin sama valla ka sünnikohana, sest seda oli eraldi mainitud. Vormi AB määrasin salvestuse põhjal.>', 1),
    ('EÜS IX 1297 (92)', NULL, 'ERA, Fon. 012 b', NULL, 'X 138', 1, 1, 1, NULL, '<(Andmed: Eesti Rahvamuusika Antoloogia)>', 1),
    ('EÜS IX 1307 (119)', NULL, 'ERA, Fon. 017 d', NULL, 'XIV 624', 1, 1, 1, NULL, '<Ei tea, mille põhjal on elukohaks märgitud Urvaste khk, Vana-Antsla (mitte vald). Algusrida oli: Mi lää esi kodo, muutsin Mi lää esä kodo>', 1),
