    ('EÜS IX 1333 (228)', NULL, 'ERA, Fon. 021 a', NULL, 'VI 858', 1, 1, 1, NULL, '<On teksti kogujad, aga pole teksti viidet. Kustutan siit kogujate nimed, sest ka tekstikogust ei leidnud - otsisin küll natuke pealiskaudselt.>', 1),
    ('EÜS IX 1334 (234)', NULL, 'ERA, Fon. 021 f', NULL, 'XIII 152', 1, 1, 1, NULL, '<Lisasin teksti viite>', 1),
