    ('EÜS IX 1349 (307)', NULL, 'ERA, Fon. 031 d', NULL, NULL, 1, 1, 1, NULL, '<See ei ole otseselt 2-realine viis, noodis on 13 positsiooni. Laulmisel kostab reaalguse kordus: aije karja, aije karja. Ma ei võtaks siia andmebaasi ossa.>', 1),
    ('EÜS IX 1352 (318)', 'EÜS IX 1455 (38)', 'ERA, Fon. 33 d', NULL, 'VII', 1, 1, 1, NULL, NULL, NULL),
    ('EÜS IX 1354 (327)', 'EÜS IX 1449 (31)', 'ERA, Fon. 035 a', NULL, 'VII', 1, 1, 1, NULL, NULL, 1),
    ('EÜS IX 1359 (348)', 'EÜS IX 1511/2 (103)', 'ERA, Fon. 038 f', NULL, 'XV 263', 1, 1, 1, NULL, '<See ei ole 2-realine viis, siin on 1 värss, kus esimest sõna korratakse, seega on siin kokku 10 positsiooni ja koos kaunistushelidega 12 nooti, ma tõstaksin selle viisi välja. Lisasin laulutüübi. Viis on "Lätsi küllä.." :-)>', 1),
    ('EÜS IX 1363 (366)', NULL, 'ERA, Fon. 041 b', NULL, 'XV 254', 1, 1, 1, NULL, '<See ei ole 2-realine viis, vaid 4-realine refrääniga, pigem siirdevormiline laul. Tõstaksin siit välja.>', 1),
    ('EÜS IX 1363 (367)', 'EÜS IX 1435/6 (11)', NULL, NULL, 'XV 264', 1, 1, 1, NULL, NULL, NULL),
    ('EÜS IX 1365 (378)', NULL, NULL, NULL, 'XIII 660', 1, 1, 1, NULL, NULL, NULL),
    ('EÜS IX 1366 (387)', NULL, 'ERA, Fon. 044 b', NULL, 'XV 265', 1, 1, 1, NULL, '<Noodistuse järgi see ei ole 2-realine viis: siin on 1 värss, kus esimest sõna korratakse või varieeritakse, seega on siin kokku 10 positsiooni. Helisalvestuse järgi on see 1-realine viis: gahh ah ggfisfis. Enne oli algusvärss: Kun ma kuna nakkan laulemahe->', 1),
    ('EÜS IX 1367 (393)', NULL, NULL, NULL, 'XI 446', 1, 1, 1, NULL, NULL, NULL),
    ('EÜS IX 1381 (453)', 'N', 'ERA, Fon. 054 c', NULL, NULL, 1, 1, 1, NULL, NULL, 1),
    ('EÜS IX 1381 (455)', NULL, 'ERA, Fon. 054 e', NULL, 'XI 104', 1, 1, 1, NULL, '<Enne oli koht Petserimaa.>', 1),
    ('EÜS IX 1382 (462)', 'EÜS X 901,4, 907', 'ERA, Fon. 055 c', NULL, '357', 1, 1, 1, NULL, '<See ei ole otseselt 2-realine viis, vaid see on 1-realine refrääniline viis refrääniga hai-lii-loo. MIna tõstaksin ta teise andmebaasi ossa. Mitmehäälne viis. Teksti viide pole kindel ja seal näib viga.>', 1),
