    ('EÜS XI 873 (12 a)', 'EÜS XI 908/9 (12); EÜS XI 873 (12 a) (noodialune)', 'ERA, Fon. 146 a', NULL, 'XI 438', 1, 1, 1, NULL, '<Helisalvestus ei kattu kõigis pisiasjades noodistusega (vt teisi märkusi). Lisasin teksti esitaja, lisasin tema valla ja küla. Viisi esitaja kohta pole rohkem andmeid. Sama viis on number 12b, aga nojah, seda pole salvestatud, seega ka mitte kartoteegis ega siinses andmebaasis... Esitaja nimetäht n alakriipsuga tähistab selles kogus III väldet.>', 1),
    ('EÜS XI 873 (12 b)', 'EÜS XI 908/9 (12)', NULL, NULL, 'XI 437', 1, 1, 1, NULL, NULL, NULL),
    ('EÜS XI 875 (17)', 'EÜS XI 910/1 (14); N', 'ERA, Fon. 146 c', NULL, 'IV 106', 1, 1, 1, NULL, '<Helisalvestusel on rohkem värsse (8-10) kui noodi all, aga kvaliteet on jube, tekstikogus on ilmselt värsid vastavuses helisalvestusega.>', 1),
    ('EÜS XI 888 (66)', 'EÜS XI 888 (66)', 'ERA, Fon. 157 a', NULL, '399', 1, 1, 1, NULL, '<Riimiline või äärmisel juhul siirdevormiline laul: järjekindel anakruusiga värss ja 3/4 mõõdus viis. See, et viis on formaalselt 16 noodi pikkune, ei anna põhjust teda regiviisiks lugeda. Jätaksin välja. Sssama laul on EÜS XI 888 (65), Fon 14e - miks seda hulgas pole? Mõlemal on viide samale tekstile nr 8 - miks seda siia pole pandud?>', 1),
    ('EÜS XI 891 (81)', 'EÜS XI 945/6 (64)', 'ERA, Fon. 159 a', NULL, 'IV 103', 1, 1, 1, NULL, '<Digiteeritud salvestust OHTOS pole. Vormile lisasin ka AA, sest kohati värssi korratakse, kohati mitte.>', 1),
    ('EÜS XI 891 (83)', 'EÜS XI 947/8 (66)', 'ERA, Fon. 159 c', NULL, 'VIII 429', 1, 1, 1, NULL, '<Digiteeritud salvestust OHTOS pole.>', 1),
    ('EÜS XI 891 (84)', 'EÜS XI 950/2 (69); N', 'ERA, Fon. 159 d', NULL, 'II 217', 1, 1, 1, NULL, '<Digiteeritud salvestust OHTOS pole. Lisasin trad. tegevuse.>', 1),
    ('EÜS XI 897 (96)', 'EÜS XI 962/3 (77)', 'ERA, Fon. 164 a', NULL, 'IV 412', 1, 1, 1, NULL, '<Helisalvestusel on rohkem värsse (6) kui noodi all (2) . Parandasin vormi AA-ks AB-st, sest kordus on nii noodis kui helisalvestusel. Üsna imelik tekst. Lisasin siia trad. tegevuse.>', 1),
    ('EÜS XI 897 (97)', NULL, 'ERA, Fon. 164 b', NULL, 'IV 84', 1, 1, 1, NULL, '<Helisalvestusel on sama tekst, mis selle noodi all, kuid rohkem värsse (6) kui noodi all (4). Salvestusel kordab laulik kõiki värsse., seetõttu lisasin vormile AA. Noodis ei ole kordamist märgitud. Viisi juures on viide neljale tekstile. Lisasin tüübinime ja trad. tegevuse.>', 1),
    ('EÜS XI 897 (97)', 'EÜS XI 964/7 (79)', 'ERA, Fon. 164 b', NULL, 'IV 84', 1, 1, 1, NULL, '<noodist erinev tekst><Lisasin tüübinime, leheküljed ja trad. tegevuse. Helisalvestusel on teine tekst.>', 1),
    ('EÜS XI 897 (97)', 'EÜS XI 967/70 (80)', 'ERA, Fon. 164 b', NULL, 'IV 84', 1, 1, 1, NULL, '<noodist erinev tekst><Lisasin tüübinime, leheküljed ja trad. tegevuse. Helisalvestusel on teine tekst.>', 1),
    ('EÜS XI 897 (97)', 'EÜS XI 970/2 (81)', 'ERA, Fon. 164 b', NULL, 'IV 84', 1, 1, 1, NULL, '<noodist erinev tekst><Lisasin tüübinime, leheküljed ja trad. tegevuse. Helisalvestusel on teine tekst.>', 1),
    ('EÜS XI 897 (98)', 'EÜS XI 976/80 (83)', 'ERA, Fon. 164 c', NULL, 'II 208', 1, 1, 1, NULL, '<Fonograafil on rohkem teksti kui noodistusel, laulja vist vähemalt osasid värsse kordab; noodistus tundub ilma korduseta.>', 1),
    ('EÜS XI 897 (99)', 'EÜS XI 980 (84)', 'ERA, Fon. 164 d', NULL, 'VIII 322', 1, 1, 1, NULL, '<Fonograafil on rohkem teksti (12 värssi) kui noodistusel (2).>', 1),
