    ('RKM II 57, 15 (2)', 'RKM II 57, 15/7 (2)', NULL, NULL, NULL, 1, 1, 1, '<Vissel, Anu 1982. Eesti karjaselaulud 1. Setu karjaselaulud>', '<Tavaliselt on rohkem kui 8positsioonilised värsid, kus värsi algussõna kordub. Ainult algusvärss on 8positsiooniline. Väga täpne, nagu oleks helisalvestuse transkriptsioon. Lisasin teksti viite.>', 1),
    ('RKM II 57, 257 (29)', 'RKM II 57, 257/8 (29)', NULL, NULL, 'VI 999', 1, 1, 1, '<Salve, Krsiti, Sarv, Vaike 1987. Setu lauludega muinasjutud>', '<Lisasin teksti viite.>', 1),
    ('RKM II 57, 31 (7)', 'RKM II 57, 31 (7)', NULL, NULL, 'VI 863', 1, 1, 1, '<Vissel, Anu 1982. Eesti karjaselaulud 1. Setu karjaselaulud>', '<Lisasin teksti viite. Väga täpne, nagu oleks helisalvestuse transkriptsioon.>', 1),
    ('RKM II 57, 329 (1)', 'RKM II 57, 329/31 (1)', NULL, NULL, NULL, 1, 1, 1, '<Vissel, Anu 1982. Eesti karjaselaulud 1. Setu karjaselaulud>', '<Tavaliselt on rohkem kui 8silbilised värsid: koos lisasilpidega 9 või 10 positsiooni.>', 1),
    ('RKM II 57, 342 (6)', 'RKM II 57, 342 (6)', NULL, NULL, NULL, 1, 1, 1, '<Vissel, Anu 1982. Eesti karjaselaulud 1. Setu karjaselaulud>', '<See on seto laulutüüp, kus tavaliselt on rohkem kui 8positsioonilised read, kuigi see siin lühikeses jupis ei tule hästi ilmsiks. Lisasin teksti viite.>', 1),
    ('RKM II 57, 369 (1)', 'RKM II 57, 369 (1)', NULL, NULL, 'X 83', 1, 1, 1, '<VK XI>', '<Parandasin viisi viite RKM II 57, 368 (1). Esitaja nimi on, aga andmeid viisi juures ei leia.>', 1),
